    ('714', 'Noibat', 'Flying', 'Dragon', '40', '30', '35', '45', '40', '55', '245', '0.5', '8.0', '49.0', 'frisk|infiltrator|telepathy', 'telepathy', 'gen-vi', 'false', 'false', 'false', 'purple', 'wings', 'flying|dragon', NULL, 'medium', '190', '70', 'Sound Wave PokÃ©mon', '367', 'They live in pitch-black caves. Their enormous ears can emit ultrasonic waves of 200,000 hertz.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/714.png'),
