    ('738', 'Vikavolt', 'Bug', 'Electric', '77', '70', '90', '145', '75', '43', '500', '1.5', '45.0', '225.0', 'levitate', NULL, 'gen-vii', 'false', 'false', 'false', 'blue', 'armor', 'bug', NULL, 'medium', '45', '70', 'Stag Beetle PokÃ©mon', '379', 'It zips around, on sharp lookout for an opening. It concentrates electrical energy within its large jaws and uses it to zap its enemies.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/738.png'),
