    ('741', 'Oricorio-Baile', 'Fire', 'Flying', '75', '70', '70', '98', '70', '93', '476', '0.6', '3.4', '167.0', 'dancer', NULL, 'gen-vii', 'false', 'false', 'false', 'red', 'wings', 'flying', NULL, 'medium', '45', '70', 'Dancing PokÃ©mon', '381', 'It beats its wings together to create fire. As it moves in the steps of its beautiful dance, it bathes opponents in intense flames.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/741.png'),
