    ('781', 'Dhelmise', 'Ghost', 'Grass', '70', '131', '100', '86', '90', '40', '517', '3.9', '210.0', '181.0', 'steelworker', NULL, 'gen-vii', 'false', 'false', 'false', 'green', 'blob', 'mineral', NULL, 'medium', '25', '70', 'Sea Creeper PokÃ©mon', '407', 'Swinging its massive anchor, it can KO Wailord in a single blow. What appears to be green seaweed is actually its body.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/781.png'),
