    ('805', 'Stakataka', 'Rock', 'Steel', '61', '131', '211', '53', '101', '13', '570', '5.5', '820.0', '257.0', 'beast-boost', NULL, 'gen-vii', 'false', 'false', 'false', 'gray', 'quadruped', 'no-eggs', NULL, 'slow', '30', '0', 'Rampart PokÃ©mon', '425', 'It appeared from an Ultra Wormhole. Each one appears to be made up of many life-forms stacked one on top of each other.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/805.png'),
    ('806', 'Blacephalon', 'Fire', 'Ghost', '53', '127', '53', '151', '79', '107', '570', '1.8', '13.0', '257.0', 'beast-boost', NULL, 'gen-vii', 'false', 'false', 'false', 'white', 'humanoid', 'no-eggs', NULL, 'slow', '30', '0', 'Fireworks PokÃ©mon', '426', 'It slithers toward people. Then, without warning, it triggers the explosion of its own head. Itâ€™s apparently one kind of Ultra Beast.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/806.png'),
    ('807', 'Zeraora', 'Electric', NULL, '88', '112', '75', '102', '80', '143', '600', '1.5', '44.5', '270.0', 'volt-absorb', NULL, 'gen-vii', 'false', 'true', 'false', 'yellow', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Thunderclap PokÃ©mon', '427', 'It electrifies its claws and tears its opponents apart with them. Even if they dodge its attack, theyâ€™ll be electrocuted by the flying sparks.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/807.png'),
    ('808', 'Meltan', 'Steel', NULL, '46', '65', '65', '55', '35', '34', '300', '0.2', '8.0', '135.0', 'magnet-pull', NULL, 'gen-vii', 'false', 'true', 'false', 'gray', 'ball', 'no-eggs', NULL, 'slow', '3', '0', 'Hex Nut PokÃ©mon', '428', 'It melts particles of iron and other metals found in the subsoil, so it can absorb them into its body of molten steel.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/808.png'),
    ('809', 'Melmetal', 'Steel', NULL, '135', '143', '143', '80', '65', '34', '600', '2.5', '800.0', '270.0', 'iron-fist', NULL, 'gen-vii', 'false', 'true', 'false', 'gray', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Hex Nut PokÃ©mon', '429', 'Revered long ago for its capacity to create iron from nothing, for some reason it has come back to life after 3,000 years.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/809.png'),
    ('810', 'Grookey', 'Grass', NULL, '50', '65', '50', '40', '40', '65', '310', '0.3', '5.0', '62.0', 'overgrow|grassy-surge', 'grassy-surge', 'gen-viii', 'false', 'false', 'false', 'green', 'upright', 'ground|plant', NULL, 'medium-slow', '45', '50', 'Chimp PokÃ©mon', '430', 'When it uses its special stick to strike up a beat, the sound waves produced carry revitalizing energy to the plants and flowers in the area.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/810.png'),
    ('811', 'Thwackey', 'Grass', NULL, '70', '85', '70', '55', '60', '80', '420', '0.7', '14.0', '147.0', 'overgrow|grassy-surge', 'grassy-surge', 'gen-viii', 'false', 'false', 'false', 'green', 'upright', 'ground|plant', NULL, 'medium-slow', '45', '50', 'Beat PokÃ©mon', '430', 'The faster a Thwackey can beat out a rhythm with its two sticks, the more respect it wins from its peers.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/811.png'),
