    ('867', 'Runerigus', 'Ground', 'Ghost', '58', '95', '145', '50', '105', '30', '483', '1.6', '66.6', '169.0', 'wandering-spirit', NULL, 'gen-viii', 'false', 'false', 'false', 'gray', 'blob', 'mineral|indeterminate', NULL, 'medium', '90', '50', 'Grudge PokÃ©mon', '287', 'A powerful curse was woven into an ancient painting. After absorbing the spirit of a Yamask, the painting began to move.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/867.png'),
