    ('10276', 'Terapagos-Terastal', 'Normal', NULL, '95', '95', '110', '105', '110', '85', '600', '0.3', '16.0', '90.0', 'tera-shell', NULL, 'gen-ix', 'true', 'false', 'false', 'blue', 'quadruped', 'no-eggs', NULL, 'slow', '255', '50', 'Tera PokÃ©mon', '548', 'Terapagos protects itself using its power to transform energy into hard crystals. This PokÃ©mon is the source of the Terastal phenomenon.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/10276.png'),
    ('10277', 'Terapagos-Stellar', 'Normal', NULL, '160', '105', '110', '130', '110', '85', '700', '1.7', '77.0', '90.0', 'teraform-zero', NULL, 'gen-ix', 'true', 'false', 'false', 'blue', 'quadruped', 'no-eggs', NULL, 'slow', '255', '50', 'Tera PokÃ©mon', '548', 'Terapagos protects itself using its power to transform energy into hard crystals. This PokÃ©mon is the source of the Terastal phenomenon.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/10277.png'),
    ('10278', 'Clefable-Mega', 'Fairy', 'Flying', '95', '80', '93', '135', '110', '70', '583', '1.7', '42.3', NULL, 'magic-bounce', NULL, 'gen-i', 'false', 'false', 'false', 'pink', 'upright', 'fairy', 'mountain', 'fast', '25', '140', 'Fairy PokÃ©mon', '14', 'A timid fairy POKÃ©MON that is rarely seen. It will run and hide the moment it senses people.', NULL),
    ('10279', 'Victreebel-Mega', 'Grass', 'Poison', '80', '125', '85', '135', '95', '70', '590', '4.5', '125.5', NULL, 'innards-out', NULL, 'gen-i', 'false', 'false', 'false', 'green', 'blob', 'plant', 'forest', 'medium-slow', '45', '70', 'Flycatcher PokÃ©mon', '29', 'Said to live in huge colonies deep in jungles, although no one has ever returned from there.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/10279.png'),
    ('10280', 'Starmie-Mega', 'Water', 'Psychic', '60', '100', '105', '130', '105', '120', '620', '2.3', '80.0', NULL, 'huge-power', NULL, 'gen-i', 'false', 'false', 'false', 'purple', 'blob', 'water3', 'sea', 'slow', '60', '70', 'Mysterious PokÃ©mon', '56', 'Its central core glows with the seven colors of the rainbow. Some people value the core as a gem.', NULL),
    ('10281', 'Dragonite-Mega', 'Dragon', 'Flying', '91', '124', '115', '145', '125', '100', '700', '2.2', '290.0', NULL, 'multiscale', NULL, 'gen-i', 'false', 'false', 'false', 'brown', 'upright', 'water1|dragon', 'waters-edge', 'slow', '45', '35', 'Dragon PokÃ©mon', '76', 'An extremely rarely seen marine POKÃ©MON. Its intelligence is said to match that of humans.', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/10281.png'),
    ('10282', 'Meganium-Mega', 'Grass', 'Fairy', '80', '92', '115', '143', '115', '80', '625', '2.4', '201.0', NULL, 'mega-sol', NULL, 'gen-ii', 'false', 'false', 'false', 'green', 'quadruped', 'monster|plant', 'grassland', 'medium-slow', '45', '70', 'Herb PokÃ©mon', '79', 'The aroma that rises from its petals contains a substance that calms aggressive feelings.', NULL),
    ('10283', 'Feraligatr-Mega', 'Water', 'Dragon', '85', '160', '125', '89', '93', '78', '630', '2.3', '108.8', NULL, 'dragonize', NULL, 'gen-ii', 'false', 'false', 'false', 'blue', 'upright', 'monster|water1', 'waters-edge', 'medium-slow', '45', '70', 'Big Jaw PokÃ©mon', '81', 'When it bites with its massive and powerful jaws, it shakes its head and savagely tears its victim up.', NULL),
    ('10284', 'Skarmory-Mega', 'Steel', 'Flying', '65', '140', '110', '40', '100', '110', '565', '1.7', '40.4', NULL, 'stalwart', NULL, 'gen-ii', 'false', 'false', 'false', 'gray', 'wings', 'flying', 'rough-terrain', 'slow', '25', '70', 'Armor Bird PokÃ©mon', '117', 'Its sturdy wings look heavy, but they are actually hollow and light, allowing it to fly freely in the sky.', NULL),
    ('10285', 'Froslass-Mega', 'Ice', 'Ghost', '70', '80', '70', '140', '100', '120', '580', '2.6', '29.6', NULL, 'snow-warning', NULL, 'gen-iv', 'false', 'false', 'false', 'white', 'arms', 'fairy|mineral', NULL, 'medium', '75', '70', 'Snow Land PokÃ©mon', '186', 'It freezes foes with an icy breath nearly -60 degrees F. What seems to be its body is actually hollow.', NULL),
    ('10286', 'Emboar-Mega', 'Fire', 'Fighting', '110', '148', '75', '110', '110', '75', '628', '1.8', '180.3', NULL, 'mold-breaker', NULL, 'gen-v', 'false', 'false', 'false', 'red', 'upright', 'ground', NULL, 'medium-slow', '45', '70', 'Mega Fire Pig PokÃ©mon', '257', 'It can throw a fire punch by setting its fists on fire with its fiery chin. It cares deeply about its friends.', NULL),
    ('10287', 'Excadrill-Mega', 'Ground', 'Steel', '110', '165', '100', '65', '65', '103', '608', '0.9', '60.0', NULL, 'piercing-drill', NULL, 'gen-v', 'false', 'false', 'false', 'gray', 'humanoid', 'ground', NULL, 'medium', '60', '70', 'Subterrene PokÃ©mon', '270', 'It can help in tunnel construction. Its drill has evolved into steel strong enough to bore through iron plates.', NULL),
    ('10288', 'Scolipede-Mega', 'Bug', 'Poison', '60', '140', '149', '75', '99', '62', '585', '3.2', '230.5', NULL, NULL, NULL, 'gen-v', 'false', 'false', 'false', 'red', 'armor', 'bug', NULL, 'medium-slow', '45', '70', 'Megapede PokÃ©mon', '277', 'With quick movements, it chases down its foes, attacking relentlessly with its horns until it prevails.', NULL),
    ('10289', 'Scrafty-Mega', 'Dark', 'Fighting', '65', '130', '135', '55', '135', '68', '588', '1.1', '31.0', NULL, NULL, NULL, 'gen-v', 'false', 'false', 'false', 'red', 'upright', 'ground|dragon', NULL, 'medium', '90', '70', 'Hoodlum PokÃ©mon', '285', 'Groups of them beat up anything that enters their territory. Each can spit acidic liquid from its mouth.', NULL),
    ('10290', 'Eelektross-Mega', 'Electric', NULL, '85', '145', '80', '135', '90', '80', '615', '3.0', '180.0', NULL, NULL, NULL, 'gen-v', 'false', 'false', 'false', 'blue', 'fish', 'indeterminate', NULL, 'slow', '30', '70', 'EleFish PokÃ©mon', '306', 'They crawl out of the ocean using their arms. They will attack prey on shore and immediately drag it into the ocean.', NULL),
    ('10291', 'Chandelure-Mega', 'Ghost', 'Fire', '60', '75', '110', '175', '110', '90', '620', '2.5', '69.6', NULL, 'infiltrator', NULL, 'gen-v', 'false', 'false', 'false', 'black', 'arms', 'indeterminate', NULL, 'medium-slow', '45', '70', 'Luring PokÃ©mon', '308', 'It absorbs a spirit, which it then burns. By waving the flames on its arms, it puts its foes into a hypnotic trance.', NULL),
    ('10292', 'Chesnaught-Mega', 'Grass', 'Fighting', '88', '137', '172', '74', '115', '44', '630', '1.6', '90.0', NULL, 'bulletproof', NULL, 'gen-vi', 'false', 'false', 'false', 'green', 'upright', 'ground', NULL, 'medium-slow', '45', '70', 'Spiny Armor PokÃ©mon', '337', 'Its Tackle is forceful enough to flip a 50-ton tank. It shields its allies from danger with its own body.', NULL),
    ('10293', 'Delphox-Mega', 'Fire', 'Psychic', '75', '69', '72', '159', '125', '134', '634', '1.5', '39.0', NULL, 'levitate', NULL, 'gen-vi', 'false', 'false', 'false', 'red', 'upright', 'ground', NULL, 'medium-slow', '45', '70', 'Fox PokÃ©mon', '338', 'It gazes into the flame at the tip of its branch to achieve a focused state, which allows it to see into the future.', NULL),
    ('10294', 'Greninja-Mega', 'Water', 'Dark', '72', '125', '77', '133', '81', '142', '630', '1.5', '40.0', NULL, 'protean', NULL, 'gen-vi', 'false', 'false', 'false', 'blue', 'humanoid', 'water1', NULL, 'medium-slow', '45', '70', 'Ninja PokÃ©mon', '339', 'It creates throwing stars out of compressed water. When it spins them and throws them at high speed, these stars can split metal in two.', NULL),
    ('10295', 'Pyroar-Mega', 'Fire', 'Normal', '86', '88', '92', '129', '86', '126', '607', '1.5', '93.3', NULL, NULL, NULL, 'gen-vi', 'false', 'false', 'false', 'brown', 'quadruped', 'ground', NULL, 'medium-slow', '65', '70', 'Royal PokÃ©mon', '343', 'The male with the largest mane of fire is the leader of the pride.', NULL),
    ('10296', 'Floette-Mega', 'Fairy', NULL, '74', '85', '87', '155', '148', '102', '651', '0.2', '100.8', NULL, 'fairy-aura', NULL, 'gen-vi', 'false', 'false', 'false', 'white', 'arms', 'fairy', NULL, 'medium', '120', '70', 'Single Bloom PokÃ©mon', '344', 'It flutters around fields of flowers and cares for flowers that are starting to wilt. It draws out the hidden power of flowers to battle.', NULL),
    ('10297', 'Malamar-Mega', 'Dark', 'Psychic', '86', '102', '88', '98', '120', '88', '582', '2.9', '69.8', NULL, NULL, NULL, 'gen-vi', 'false', 'false', 'false', 'blue', 'blob', 'water1|water2', NULL, 'medium', '80', '70', 'Overturning PokÃ©mon', '352', 'It wields the most compelling hypnotic powers of any PokÃ©mon, and it forces others to do whatever it wants.', NULL),
    ('10298', 'Barbaracle-Mega', 'Rock', 'Fighting', '72', '140', '130', '64', '106', '88', '600', '2.2', '100.0', NULL, NULL, NULL, 'gen-vi', 'false', 'false', 'false', 'brown', 'heads', 'water3', NULL, 'medium', '45', '70', 'Collective PokÃ©mon', '353', 'When they evolve, two Binacle multiply into seven. They fight with the power of seven Binacle.', NULL),
    ('10299', 'Dragalge-Mega', 'Poison', 'Dragon', '65', '85', '105', '132', '163', '44', '594', '2.1', '100.3', NULL, NULL, NULL, 'gen-vi', 'false', 'false', 'false', 'brown', 'blob', 'water1|dragon', NULL, 'medium', '55', '70', 'Mock Kelp PokÃ©mon', '354', 'Their poison is strong enough to eat through the hull of a tanker, and they spit it indiscriminately at anything that enters their territory.', NULL),
    ('10300', 'Hawlucha-Mega', 'Fighting', 'Flying', '78', '137', '100', '74', '93', '118', '600', '1.0', '25.0', NULL, 'no-guard', NULL, 'gen-vi', 'false', 'false', 'false', 'green', 'humanoid', 'flying|humanshape', NULL, 'medium', '100', '70', 'Wrestling PokÃ©mon', '359', 'Although its body is small, its proficient fighting skills enable it to keep up with big bruisers like Machamp and Hariyama.', NULL),
    ('10301', 'Zygarde-Mega', 'Dragon', 'Ground', '216', '70', '91', '216', '85', '100', '778', '7.7', '610.0', NULL, NULL, NULL, 'gen-vi', 'true', 'false', 'false', 'green', 'squiggle', 'no-eggs', NULL, 'slow', '3', '0', 'Order PokÃ©mon', '370', 'When the Kalos regionâ€™s ecosystem falls into disarray, it appears and reveals its secret power.', NULL),
    ('10302', 'Drampa-Mega', 'Normal', 'Dragon', '78', '85', '110', '160', '116', '36', '585', '3.0', '240.5', NULL, 'berserk', NULL, 'gen-vii', 'false', 'false', 'false', 'white', 'squiggle', 'monster|dragon', NULL, 'medium', '70', '70', 'Placid PokÃ©mon', '406', 'It has a compassionate personality, but if it is angered, it completely destroys its surroundings with its intense breath.', NULL),
    ('10303', 'Falinks-Mega', 'Fighting', NULL, '65', '135', '135', '70', '65', '100', '570', '1.6', '99.0', NULL, NULL, NULL, 'gen-viii', 'false', 'false', 'false', 'yellow', 'heads', 'fairy|mineral', NULL, 'medium', '45', '50', 'Formation PokÃ©mon', '453', 'Five of them are troopers, and one is the brass. The brassâ€™s orders are absolute.', NULL),
    ('10304', 'Raichu-Mega-X', 'Electric', NULL, '60', '135', '95', '90', '95', '110', '585', '1.2', '38.0', NULL, NULL, NULL, 'gen-i', 'false', 'false', 'false', 'yellow', 'upright', 'ground|fairy', 'forest', 'medium', '75', '70', 'Mouse PokÃ©mon', '10', 'Its long tail serves as a ground to protect itself from its own high-voltage power.', NULL),
    ('10305', 'Raichu-Mega-Y', 'Electric', NULL, '60', '100', '55', '160', '80', '130', '585', '1.0', '26.0', NULL, NULL, NULL, 'gen-i', 'false', 'false', 'false', 'yellow', 'upright', 'ground|fairy', 'forest', 'medium', '75', '70', 'Mouse PokÃ©mon', '10', 'Its long tail serves as a ground to protect itself from its own high-voltage power.', NULL),
    ('10306', 'Chimecho-Mega', 'Psychic', 'Steel', '75', '50', '110', '135', '120', '65', '555', '1.2', '8.0', NULL, 'levitate', NULL, 'gen-iii', 'false', 'false', 'false', 'blue', 'arms', 'indeterminate', 'grassland', 'fast', '45', '70', 'Wind Chime PokÃ©mon', '184', 'CHIMECHO makes its cries echo inside its hollow body. When this POKÃ©MON becomes enraged, its cries result in ultrasonic waves that have the power to knock foes flying.', NULL),
    ('10307', 'Absol-Mega-Z', 'Dark', 'Ghost', '65', '154', '60', '75', '60', '151', '565', '1.2', '49.0', NULL, NULL, NULL, 'gen-iii', 'false', 'false', 'false', 'white', 'quadruped', 'ground', 'mountain', 'medium-slow', '30', '35', 'Disaster PokÃ©mon', '185', 'Every time ABSOL appears before people, it is followed by a disaster such as an earthquake or a tidal wave. As a result, it came to be known as the disaster POKÃ©MON.', NULL),
    ('10308', 'Staraptor-Mega', 'Fighting', 'Flying', '85', '140', '100', '60', '90', '110', '585', '1.9', '50.0', NULL, NULL, NULL, 'gen-iv', 'false', 'false', 'false', 'brown', 'wings', 'flying', NULL, 'medium-slow', '45', '70', 'Predator PokÃ©mon', '206', 'It has a savage nature. It will courageously challenge foes that are much larger.', NULL),
    ('10309', 'Garchomp-Mega-Z', 'Dragon', NULL, '108', '130', '85', '141', '85', '151', '700', '1.9', '99.0', NULL, NULL, NULL, 'gen-iv', 'false', 'false', 'false', 'blue', 'upright', 'monster|dragon', NULL, 'slow', '45', '70', 'Mach PokÃ©mon', '230', 'When it folds up its body and extends its wings, it looks like a jet plane. It flies at sonic speed.', NULL),
    ('10310', 'Lucario-Mega-Z', 'Fighting', 'Steel', '70', '100', '70', '164', '70', '151', '625', '1.3', '49.4', NULL, NULL, NULL, 'gen-iv', 'false', 'false', 'false', 'blue', 'upright', 'ground|humanshape', NULL, 'medium-slow', '45', '70', 'Aura PokÃ©mon', '232', 'It has the ability to sense the auras of all things. It understands human speech.', NULL),
    ('10311', 'Heatran-Mega', 'Fire', 'Steel', '91', '120', '106', '175', '141', '67', '700', '2.8', '570.0', NULL, NULL, NULL, 'gen-iv', 'true', 'false', 'false', 'brown', 'quadruped', 'no-eggs', NULL, 'slow', '3', '100', 'Lava Dome PokÃ©mon', '246', 'It dwells in volcanic caves. It digs in with its cross-shaped feet to crawl on ceilings and walls.', NULL),
    ('10312', 'Darkrai-Mega', 'Dark', NULL, '70', '120', '130', '165', '130', '85', '700', '3.0', '240.0', NULL, NULL, NULL, 'gen-iv', 'false', 'true', 'false', 'black', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Pitch-Black PokÃ©mon', '252', 'It can lull people to sleep and make them dream. It is active during nights of the new moon.', NULL),
    ('10313', 'Golurk-Mega', 'Ground', 'Ghost', '89', '159', '105', '70', '105', '55', '583', '4.0', '330.0', NULL, 'unseen-fist', NULL, 'gen-v', 'false', 'false', 'false', 'green', 'humanoid', 'mineral', NULL, 'medium', '90', '70', 'Automaton PokÃ©mon', '316', 'It flies across the sky at Mach speeds. Removing the seal on its chest makes its internal energy go out of control.', NULL),
    ('10314', 'Meowstic-Mega', 'Psychic', NULL, '74', '48', '76', '143', '101', '124', '566', '0.8', '10.1', NULL, 'trace', NULL, 'gen-vi', 'false', 'false', 'false', 'blue', 'upright', 'ground', NULL, 'medium', '75', '70', 'Constraint PokÃ©mon', '348', 'When in danger, it raises its ears and releases enough psychic power to grind a 10-ton truck into dust.', NULL),
    ('10315', 'Crabominable-Mega', 'Fighting', 'Ice', '97', '157', '122', '62', '107', '33', '578', '2.6', '252.8', NULL, 'iron-fist', NULL, 'gen-vii', 'false', 'false', 'false', 'white', 'armor', 'water3', NULL, 'medium', '60', '70', 'Woolly Crab PokÃ©mon', '380', 'It aimed for the top but got lost and ended up on a snowy mountain. Being forced to endure the cold, this PokÃ©mon evolved and grew fur.', NULL),
    ('10316', 'Golisopod-Mega', 'Bug', 'Steel', '75', '150', '175', '70', '120', '40', '630', '2.3', '148.0', NULL, NULL, NULL, 'gen-vii', 'false', 'false', 'false', 'gray', 'humanoid', 'bug|water3', NULL, 'medium', '45', '70', 'Hard Scale PokÃ©mon', '396', 'With a flashing slash of its giant sharp claws, it cleaves seawaterâ€”or even airâ€”right in two.', NULL),
    ('10317', 'Magearna-Mega', 'Steel', 'Fairy', '80', '125', '115', '170', '115', '95', '700', '1.3', '248.1', NULL, NULL, NULL, 'gen-vii', 'false', 'true', 'false', 'gray', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Artificial PokÃ©mon', '422', 'This artificial PokÃ©mon, constructed more than 500 years ago, can understand human speech but cannot itself speak.', NULL),
    ('10318', 'Magearna-Original-Mega', 'Steel', 'Fairy', '80', '125', '115', '170', '115', '95', '700', '1.3', '248.1', NULL, NULL, NULL, 'gen-vii', 'false', 'true', 'false', 'gray', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Artificial PokÃ©mon', '422', 'This artificial PokÃ©mon, constructed more than 500 years ago, can understand human speech but cannot itself speak.', NULL),
    ('10319', 'Zeraora-Mega', 'Electric', NULL, '88', '157', '75', '147', '80', '153', '700', '1.5', '44.5', NULL, NULL, NULL, 'gen-vii', 'false', 'true', 'false', 'yellow', 'humanoid', 'no-eggs', NULL, 'slow', '3', '0', 'Thunderclap PokÃ©mon', '427', 'It electrifies its claws and tears its opponents apart with them. Even if they dodge its attack, theyâ€™ll be electrocuted by the flying sparks.', NULL),
    ('10320', 'Scovillain-Mega', 'Grass', 'Fire', '65', '138', '85', '138', '85', '75', '586', '1.2', '22.0', NULL, 'spicy-spray', NULL, 'gen-ix', 'false', 'false', 'false', 'green', 'upright', 'plant', NULL, 'medium', '75', '50', 'Spicy Pepper PokÃ©mon', '498', 'The red head converts spicy chemicals into fire energy and blasts the surrounding area with a super spicy stream of flame.', NULL),
    ('10321', 'Glimmora-Mega', 'Rock', 'Poison', '83', '90', '105', '150', '96', '101', '625', '2.8', '77.0', NULL, 'adaptability', NULL, 'gen-ix', 'false', 'false', 'false', 'blue', 'ball', 'mineral', NULL, 'medium-slow', '25', '50', 'Ore PokÃ©mon', '508', 'When this PokÃ©mon detects danger, it will open up its crystalline petals and fire beams from its conical body.', NULL),
    ('10322', 'Tatsugiri-Curly-Mega', 'Dragon', 'Water', '68', '65', '90', '135', '125', '92', '575', '0.6', '24.0', NULL, NULL, NULL, 'gen-ix', 'false', 'false', 'false', 'pink', 'fish', 'water2', NULL, 'medium-slow', '100', '50', 'Mimicry PokÃ©mon', '514', 'This is a small dragon PokÃ©mon. It lives inside the mouth of Dondozo to protect itself from enemies on the outside.', NULL),
    ('10323', 'Tatsugiri-Droopy-Mega', 'Dragon', 'Water', '68', '65', '90', '135', '125', '92', '575', '0.6', '24.0', NULL, NULL, NULL, 'gen-ix', 'false', 'false', 'false', 'pink', 'fish', 'water2', NULL, 'medium-slow', '100', '50', 'Mimicry PokÃ©mon', '514', 'This is a small dragon PokÃ©mon. It lives inside the mouth of Dondozo to protect itself from enemies on the outside.', NULL),
    ('10324', 'Tatsugiri-Stretchy-Mega', 'Dragon', 'Water', '68', '65', '90', '135', '125', '92', '575', '0.6', '24.0', NULL, NULL, NULL, 'gen-ix', 'false', 'false', 'false', 'pink', 'fish', 'water2', NULL, 'medium-slow', '100', '50', 'Mimicry PokÃ©mon', '514', 'This is a small dragon PokÃ©mon. It lives inside the mouth of Dondozo to protect itself from enemies on the outside.', NULL),
