-- Limpieza sencilla de la capa de carga.
-- type_2 vacío se convierte en NULL. Esto no se considera error: muchos Pokemon solo tienen un tipo.
BEGIN;
UPDATE carga.stg_pokemon_raw
SET type_2 = NULL
WHERE TRIM(COALESCE(type_2, '')) = '';
COMMIT;

-- Ejemplo controlado de INSERT y DELETE: insertamos un registro de prueba y lo borramos.
-- Sirve para demostrar DELETE sin alterar el dataset final.
BEGIN;
INSERT INTO carga.stg_pokemon_raw (pokedex_number, name, type_1, hp, attack, defense, sp_attack, sp_defense, speed, base_stat_total, generation)
VALUES ('99999', 'registro_prueba', 'Normal', '1', '1', '1', '1', '1', '1', '6', 'gen-i');

DELETE FROM carga.stg_pokemon_raw
WHERE name = 'registro_prueba';
COMMIT;

