(6, 'Generacion 6', 'Kalos'),
(7, 'Generacion 7', 'Alola'),
(8, 'Generacion 8', 'Galar'),
(9, 'Generacion 9', 'Paldea');

-- Dimensión nivel de poder. Es un criterio propio para clasificar Pokemon por total_estadisticas.
INSERT INTO modelo.dim_nivel_poder (nombre_nivel, stat_min, stat_max) VALUES
('Bajo', 0, 330),
('Medio', 331, 450),
('Alto', 451, 580),
('Muy alto', 581, 2000);

-- Dimensión tipo: se extraen tipos principales y secundarios del CSV.
INSERT INTO modelo.dim_tipo (nombre_tipo)
SELECT DISTINCT nombre_tipo
FROM (
    SELECT INITCAP(TRIM(type_1)) AS nombre_tipo
    FROM carga.stg_pokemon_raw
    WHERE TRIM(COALESCE(type_1, '')) <> ''
    UNION
    SELECT INITCAP(TRIM(type_2)) AS nombre_tipo
    FROM carga.stg_pokemon_raw
    WHERE TRIM(COALESCE(type_2, '')) <> ''
) tipos
ORDER BY nombre_tipo;

-- Dimensión Pokemon. raw_id_origen permite mantener la trazabilidad con la tabla cruda.
INSERT INTO modelo.dim_pokemon (
    raw_id_origen, numero_pokedex, nombre, es_legendario, es_mitico, es_bebe,
    color, forma, grupo_huevo, habitat, ritmo_crecimiento, genero, texto_descriptivo, url_sprite
)
SELECT
    raw_id,
    CAST(pokedex_number AS INT),
    name,
    LOWER(COALESCE(is_legendary, 'false')) = 'true',
    LOWER(COALESCE(is_mythical, 'false')) = 'true',
    LOWER(COALESCE(is_baby, 'false')) = 'true',
    color,
    shape,
    egg_groups,
    habitat,
    growth_rate,
    genus,
    flavor_text,
    sprite_url
FROM carga.stg_pokemon_raw;

-- Dimensión habilidad: separamos la columna abilities por el caracter | y también incluimos hidden_ability.
INSERT INTO modelo.dim_habilidad (nombre_habilidad)
SELECT DISTINCT INITCAP(TRIM(habilidad)) AS nombre_habilidad
FROM (
    SELECT UNNEST(STRING_TO_ARRAY(abilities, '|')) AS habilidad
    FROM carga.stg_pokemon_raw
    WHERE TRIM(COALESCE(abilities, '')) <> ''
    UNION ALL
    SELECT hidden_ability AS habilidad
    FROM carga.stg_pokemon_raw
    WHERE TRIM(COALESCE(hidden_ability, '')) <> ''
) h
WHERE TRIM(COALESCE(habilidad, '')) <> ''
ORDER BY nombre_habilidad;

-- ==========================================================
-- CARGA DE TABLA DE HECHOS
-- ==========================================================

-- Nota: base_experience se mantiene en la tabla de carga por trazabilidad, pero no se pasa a la tabla de hechos porque queda fuera del alcance analítico.
-- Tampoco se crea ratio_ataque_defensa para mantener un modelo más sencillo e interpretable.

INSERT INTO modelo.fact_estadisticas_pokemon (
    pokemon_id, tipo_1_id, tipo_2_id, generacion_id, nivel_poder_id,
    hp, ataque, defensa, ataque_especial, defensa_especial, velocidad,
    total_estadisticas, altura_m, peso_kg, fecha_carga
)
SELECT
    p.pokemon_id,
    t1.tipo_id AS tipo_1_id,
    t2.tipo_id AS tipo_2_id,
    CASE LOWER(r.generation)
        WHEN 'gen-i' THEN 1
        WHEN 'gen-ii' THEN 2
        WHEN 'gen-iii' THEN 3
        WHEN 'gen-iv' THEN 4
        WHEN 'gen-v' THEN 5
        WHEN 'gen-vi' THEN 6
        WHEN 'gen-vii' THEN 7
        WHEN 'gen-viii' THEN 8
        WHEN 'gen-ix' THEN 9
    END AS generacion_id,
    np.nivel_poder_id,
    CAST(r.hp AS INT),
    CAST(r.attack AS INT),
    CAST(r.defense AS INT),
    CAST(r.sp_attack AS INT),
    CAST(r.sp_defense AS INT),
    CAST(r.speed AS INT),
    CAST(r.base_stat_total AS INT),
    CAST(r.height_m AS NUMERIC),
    CAST(r.weight_kg AS NUMERIC),
    r.fecha_carga
FROM carga.stg_pokemon_raw r
INNER JOIN modelo.dim_pokemon p
    ON r.raw_id = p.raw_id_origen
INNER JOIN modelo.dim_tipo t1
    ON INITCAP(TRIM(r.type_1)) = t1.nombre_tipo
LEFT JOIN modelo.dim_tipo t2
    ON INITCAP(TRIM(r.type_2)) = t2.nombre_tipo
INNER JOIN modelo.dim_nivel_poder np
    ON CAST(r.base_stat_total AS INT) BETWEEN np.stat_min AND np.stat_max;

-- Tabla puente Pokemon-Habilidad.
INSERT INTO modelo.puente_pokemon_habilidad (pokemon_id, habilidad_id, es_oculta)
SELECT DISTINCT
    p.pokemon_id,
    h.habilidad_id,
    CASE
        WHEN r.hidden_ability IS NOT NULL
             AND TRIM(r.hidden_ability) <> ''
             AND LOWER(TRIM(h.nombre_habilidad)) = LOWER(TRIM(r.hidden_ability))
        THEN TRUE
        ELSE FALSE
    END AS es_oculta
FROM carga.stg_pokemon_raw r
INNER JOIN modelo.dim_pokemon p
    ON r.raw_id = p.raw_id_origen
CROSS JOIN LATERAL UNNEST(STRING_TO_ARRAY(COALESCE(r.abilities, ''), '|')) AS habilidad(nombre)
INNER JOIN modelo.dim_habilidad h
    ON INITCAP(TRIM(habilidad.nombre)) = h.nombre_habilidad
WHERE TRIM(COALESCE(habilidad.nombre, '')) <> '';

-- Transacción con ROLLBACK para demostrar que se puede deshacer un cambio.
-- No afecta al resultado final porque se revierte.
BEGIN;
UPDATE modelo.fact_estadisticas_pokemon
SET hp = hp + 1
WHERE estadistica_id = 1;
ROLLBACK;
